import { useEffect, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import Payment from "../Payment";
import Chatbot from "../Chatbot/Chatbot";

function StarRating({ appointmentId, doctorId, onRated }) {
  const [hovered, setHovered] = useState(0);
  const [selected, setSelected] = useState(0);
  const [submitted, setSubmitted] = useState(false);
  const token = localStorage.getItem("token");

  const submitRating = async (rating) => {
    try {
      await axios.post(
        "http://localhost:5000/api/reviews",
        { doctorId, appointmentId, rating },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setSelected(rating);
      setSubmitted(true);
      toast.success("Rating submitted! ⭐");
      if (onRated) onRated();
    } catch (err) {
      toast.error(err.response?.data?.message || "Rating failed");
    }
  };

  if (submitted) {
    return (
      <div className="mt-2 text-yellow-500 font-semibold text-sm">
        {"⭐".repeat(selected)} Rated!
      </div>
    );
  }

  return (
    <div className="mt-2">
      <p className="text-sm text-gray-500 mb-1">Rate your appointment:</p>
      <div className="flex gap-1">
        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            onClick={() => submitRating(star)}
            onMouseEnter={() => setHovered(star)}
            onMouseLeave={() => setHovered(0)}
            style={{
              fontSize: "22px",
              cursor: "pointer",
              background: "none",
              border: "none",
              padding: 0,
            }}
          >
            {star <= (hovered || selected) ? "⭐" : "☆"}
          </button>
        ))}
      </div>
    </div>
  );
}

export default function PatientDashboard() {
  const [doctors, setDoctors] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [ratedAppointments, setRatedAppointments] = useState({});
  const [form, setForm] = useState({
    doctorId: "",
    date: "",
    time: "",
    reason: "",
  });
  const [selectedAppointment, setSelectedAppointment] = useState(null);
  const token = localStorage.getItem("token");

  useEffect(() => {
    if (!token) return;
    fetchDoctors();
    fetchAppointments();
  }, []);

  const fetchDoctors = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/users/doctors");
      setDoctors(res.data);
    } catch (err) {
      toast.error("Error fetching doctors");
    }
  };

  const fetchAppointments = async () => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/appointments/patient",
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );
      setAppointments(res.data);

      const reviewChecks = {};
      for (let app of res.data) {
        if (app.status === "completed") {
          try {
            const rev = await axios.get(
              `http://localhost:5000/api/reviews/check/${app._id}`,
              { headers: { Authorization: `Bearer ${token}` } }
            );
            reviewChecks[app._id] = rev.data.reviewed;
          } catch {
            reviewChecks[app._id] = false;
          }
        }
      }
      setRatedAppointments(reviewChecks);
    } catch (err) {
      toast.error("Error fetching appointments");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.doctorId || !form.date || !form.time) {
      toast.error("Please fill all required fields");
      return;
    }
    try {
      await axios.post("http://localhost:5000/api/appointments", form, {
        headers: { Authorization: `Bearer ${token}` },
      });
      toast.success("Appointment booked successfully!");
      setForm({ doctorId: "", date: "", time: "", reason: "" });
      fetchAppointments();
    } catch (err) {
      toast.error("Booking failed");
    }
  };

  const getStatusColor = (status) => {
    if (status === "approved") return "text-green-600";
    if (status === "rejected") return "text-red-600";
    if (status === "completed") return "text-blue-600";
    return "text-yellow-600";
  };

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      <h1 className="text-3xl font-bold mb-6">Patient Dashboard</h1>

      {/* Book Appointment */}
      <div className="bg-white p-6 rounded shadow-md mb-8">
        <h2 className="text-xl font-semibold mb-4">Book Appointment</h2>
        <form onSubmit={handleSubmit}>
          <select
            className="w-full border p-2 mb-3 rounded"
            value={form.doctorId}
            onChange={(e) => setForm({ ...form, doctorId: e.target.value })}
          >
            <option value="">Select Doctor</option>
            {doctors.map((doc) => (
              <option key={doc._id} value={doc._id}>
                {doc.name}
              </option>
            ))}
          </select>

          <input
            type="date"
            className="w-full border p-2 mb-3 rounded"
            value={form.date}
            onChange={(e) => setForm({ ...form, date: e.target.value })}
          />

          <input
            type="time"
            className="w-full border p-2 mb-3 rounded"
            value={form.time}
            onChange={(e) => setForm({ ...form, time: e.target.value })}
          />

          <textarea
            placeholder="Reason (optional)"
            className="w-full border p-2 mb-3 rounded"
            value={form.reason}
            onChange={(e) => setForm({ ...form, reason: e.target.value })}
          />

          <button
            type="submit"
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
          >
            Book Now
          </button>
        </form>
      </div>

      {/* Appointments */}
      <div className="bg-white p-6 rounded shadow-md">
        <h2 className="text-xl font-semibold mb-4">My Appointments</h2>
        {appointments.length === 0 && <p>No appointments yet.</p>}

        {appointments.map((app) => (
          <div key={app._id} className="border p-4 mb-3 rounded bg-gray-50">
            <p>
              <strong>Doctor:</strong> {app.doctor?.name}
            </p>
            <p>
              <strong>Date:</strong> {new Date(app.date).toLocaleDateString()}
            </p>
            <p>
              <strong>Time:</strong> {app.time}
            </p>
            <p>
              <strong>Status:</strong>{" "}
              <span className={`font-bold ${getStatusColor(app.status)}`}>
                {app.status}
              </span>
            </p>

            {app.status === "approved" && (
              <button
                onClick={() => setSelectedAppointment(app._id)}
                className="mt-3 bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700"
              >
                Pay Now
              </button>
            )}

            {app.status === "completed" && !ratedAppointments[app._id] && (
              <StarRating
                appointmentId={app._id}
                doctorId={app.doctor?._id}
                onRated={() =>
                  setRatedAppointments((prev) => ({ ...prev, [app._id]: true }))
                }
              />
            )}

            {app.status === "completed" && ratedAppointments[app._id] && (
              <p className="mt-2 text-sm text-green-600">✅ Already rated</p>
            )}
          </div>
        ))}
      </div>

      {selectedAppointment && (
        <Payment
          appointmentId={selectedAppointment}
          onPaymentDone={() => {
            setSelectedAppointment(null);
            fetchAppointments();
          }}
        />
      )}

      <Chatbot />
    </div>
  );
}
